"use client"
import * as React from "react"
import { cn } from "@/lib/utils"

interface BentoItem {
  title: string
  description: string
  icon?: React.ReactNode
  className?: string
  children?: React.ReactNode
}

interface BentoGridProps {
  items: BentoItem[]
  className?: string
}

function BentoCard({ title, description, icon, className, children }: BentoItem) {
  const ref = React.useRef<HTMLDivElement>(null)
  const [pos, setPos] = React.useState({ x: 0, y: 0, opacity: 0 })

  const onMove = (e: React.MouseEvent) => {
    const rect = ref.current!.getBoundingClientRect()
    setPos({ x: e.clientX - rect.left, y: e.clientY - rect.top, opacity: 1 })
  }

  return (
    <div
      ref={ref}
      onMouseMove={onMove}
      onMouseLeave={() => setPos(p => ({ ...p, opacity: 0 }))}
      className={cn("group relative overflow-hidden rounded-2xl border border-white/[0.07] bg-[#0a0a0a] p-6", className)}
    >
      <div
        className="pointer-events-none absolute inset-0 transition-opacity duration-300"
        style={{
          opacity: pos.opacity,
          background: `radial-gradient(350px circle at ${pos.x}px ${pos.y}px, rgba(0,212,255,0.06), transparent 60%)`,
        }}
      />
      {icon && <div className="mb-4">{icon}</div>}
      <h3 className="text-base font-semibold mb-2">{title}</h3>
      <p className="text-sm text-[#444] leading-relaxed">{description}</p>
      {children}
    </div>
  )
}

export function BentoGrid({ items, className }: BentoGridProps) {
  return (
    <div className={cn("grid grid-cols-1 md:grid-cols-3 gap-4", className)}>
      {items.map((item, i) => (
        <BentoCard key={i} {...item} />
      ))}
    </div>
  )
}
